// Obtiene el siguiente lote de ferreterías sin coordenadas
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
if (!SUPABASE_URL || !SUPABASE_KEY) throw new Error('Faltan variables SUPABASE_URL o SUPABASE_SERVICE_KEY');

const staticData = $getWorkflowStaticData('global');
if (!staticData.offset) staticData.offset = 0;
if (!staticData.totalEnriquecidos) staticData.totalEnriquecidos = 0;
if (!staticData.totalFallidos) staticData.totalFallidos = 0;

const LIMIT = 500;
const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/ferreterias?select=id,razon_social,ciudad,departamento&lat=is.null&order=id.asc&limit=${LIMIT}&offset=${staticData.offset}`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
});

if (!Array.isArray(resp) || resp.length === 0) {
  return [{ json: { _fin: true, total_enriquecidos: staticData.totalEnriquecidos, total_fallidos: staticData.totalFallidos, mensaje: 'Todas las ferreterías ya tienen coordenadas.' } }];
}

staticData.offset += resp.length;
const tieneMas = resp.length === LIMIT;

console.log(`Lote: ${resp.length} registros sin coordenadas (offset=${staticData.offset - resp.length})`);
return resp.map(r => ({ json: { ...r, _tiene_mas: tieneMas } }));

// Busca en Google Places cada ferretería del lote
const MAPS_KEY = $env.GOOGLE_MAPS_API_KEY;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
if (!MAPS_KEY) throw new Error('Falta variable GOOGLE_MAPS_API_KEY');

const items = $input.all();
const staticData = $getWorkflowStaticData('global');
const resultados = [];

for (const item of items) {
  const { id, razon_social, ciudad, departamento } = item.json;
  if (!razon_social) continue;

  const queryStr = `${razon_social} ferreteria ${ciudad || ''} ${departamento || ''} Colombia`.trim();
  let lat = null, lng = null, formatted_address = null, google_place_id = null;

  try {
    const searchResp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://maps.googleapis.com/maps/api/place/textsearch/json?query=${encodeURIComponent(queryStr)}&key=${MAPS_KEY}&language=es&region=co`,
      headers: {}
    });

    if (searchResp.status === 'OK' && searchResp.results && searchResp.results.length > 0) {
      const place = searchResp.results[0];
      lat = place.geometry?.location?.lat || null;
      lng = place.geometry?.location?.lng || null;
      formatted_address = place.formatted_address || null;
      google_place_id   = place.place_id || null;
    }
  } catch(e) {
    console.error(`Error Maps para ${razon_social}: ${e.message}`);
  }

  // Actualizar en Supabase
  if (lat !== null && lng !== null) {
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${SUPABASE_URL}/rest/v1/ferreterias?id=eq.${id}`,
        headers: {
          'apikey': SUPABASE_KEY,
          'Authorization': `Bearer ${SUPABASE_KEY}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: JSON.stringify({ lat, lng, formatted_address, google_place_id })
      });
      staticData.totalEnriquecidos = (staticData.totalEnriquecidos || 0) + 1;
    } catch(e) {
      console.error(`Error actualizando Supabase id=${id}: ${e.message}`);
      staticData.totalFallidos = (staticData.totalFallidos || 0) + 1;
    }
  } else {
    staticData.totalFallidos = (staticData.totalFallidos || 0) + 1;
  }

  // Pequeña pausa para no saturar la API
  await new Promise(r => setTimeout(r, 200));

  resultados.push({ json: { id, razon_social, lat, lng, formatted_address, enriquecido: lat !== null } });
}

console.log(`Lote procesado. Enriquecidos total: ${staticData.totalEnriquecidos}, Fallidos: ${staticData.totalFallidos}`);
return resultados;

// Si quedan más registros en Supabase, vuelve a obtener el siguiente lote
const staticData = $getWorkflowStaticData('global');
const items = $input.all();
const tieneMas = items.some(i => i.json._tiene_mas === true) || false;
console.log(`¿Tiene más? ${tieneMas} | Offset actual: ${staticData.offset}`);
return [{ json: { _continuar: tieneMas, offset: staticData.offset, total_enriquecidos: staticData.totalEnriquecidos, total_fallidos: staticData.totalFallidos } }];

const staticData = $getWorkflowStaticData('global');
const resumen = { estado: 'ENRIQUECIMIENTO COMPLETADO', total_enriquecidos: staticData.totalEnriquecidos||0, total_fallidos: staticData.totalFallidos||0, mensaje: `Se agregaron coordenadas a ${staticData.totalEnriquecidos||0} ferreterías. ${staticData.totalFallidos||0} no encontradas en Google Maps.` };
console.log(JSON.stringify(resumen, null, 2));
return [{ json: resumen }];
